select item.evaluate_group evaluateGroup, item.evaluate_metrics evaluateMetrics, item.weight weight, item.metrics_content metricsContent, item.evaluate_dept evaluateDept, item.disp_order_no dispOrderNo, detail.score_user_id scoreUserId, detail.score_user_name scoreUserName, detail.id evaluateDetailId, detail.score detailScore, detail.status evaluateUserDetailStatus, date_format(now(), '%Y-%m-%d') evaluateDate, u.user_name userName, u.user_id userId, u.dept_name deptName, u.dept_id deptId, u.evaluate_month evaluateMonth, u.id evaluateUserId, u.status evaluateUserStatus, u.evaluate_remark evaluateRemark from t_evaluate_user_detail detail join t_evaluate_item item on detail.evaluate_item_id = item.id join t_evaluate_user u on detail.evaluate_user_id = u.id
detail.evaluate_user_id = #{evaluateUserId}
and u.evaluate_month = #{yearAndMonth}
and item.evaluate_dept = #{evaluateDept}
and ( find_in_set(#{currentUserId}, replace(detail.score_user_id, '|', ','))
or u.branch_cd = #{branchCd}
)
and u.user_name like concat('%',#{evaluateName},'%')
order by item.disp_order_no

select u.*
from t_evaluate_user_detail d
         join t_evaluate_user u on d.evaluate_user_id = u.id


        (
            find_in_set(#{currentUserId},replace(d.score_user_id,'|',',')) or u.user_id = #{currentUserId}

                or u.branch_cd = #{branchCd}

        )


        and u.evaluate_month = #{evaluateMonth}


        and u.user_name like concat('%',#{userName},'%')


        and u.status = #{evaluateStatus}


group by u.id,u.dept_id,u.assessment_user_id
order by u.dept_id,u.assessment_user_id

